import { describe, test, expect } from 'vitest';
import { Defuddle } from './src/node';
import { parseDocument } from './tests/helpers';

describe('Empty table stripping', () => {
    test('should strip tables with no text content in any cell', async () => {
        const html = `<html><head><title>Test</title></head><body><article>
            <h1>Test Article</h1>
            <p>Some content before the table.</p>
            <table class="pr_quality" title="1 validated page, 10 only proofread pages">
                <tr>
                    <td class="quality4" style="width: 8.33%"></td>
                    <td class="quality3" style="width: 83.33%"></td>
                    <td class="quality2" style="width: 0%"></td>
                    <td class="quality1" style="width: 0%"></td>
                    <td class="quality0" style="width: 8.33%"></td>
                    <td class="qualitye" style="width: 0%"></td>
                </tr>
            </table>
            <p>Some content after the table.</p>
        </article></body></html>`;

        const result = await Defuddle(parseDocument(html, 'https://example.com'), 'https://example.com', { separateMarkdown: true });

        console.log("=== Content Markdown ===");
        console.log(result.contentMarkdown);

        // The empty table should NOT appear in the output
        expect(result.contentMarkdown).not.toContain('|---');
        expect(result.contentMarkdown).not.toMatch(/^\| \s*\|/m);

        // Content before and after should be preserved
        expect(result.contentMarkdown).toContain('Some content before the table');
        expect(result.contentMarkdown).toContain('Some content after the table');
    });

    test('should preserve tables with text content', async () => {
        const html = `<html><head><title>Test</title></head><body><article>
            <h1>Test Article</h1>
            <p>Here is a comparison:</p>
            <table>
                <tr>
                    <th>Name</th>
                    <th>Value</th>
                </tr>
                <tr>
                    <td>Foo</td>
                    <td>42</td>
                </tr>
            </table>
            <p>End of article.</p>
        </article></body></html>`;

        const result = await Defuddle(parseDocument(html, 'https://example.com'), 'https://example.com', { separateMarkdown: true });

        console.log("=== Content Markdown (should have table) ===");
        console.log(result.contentMarkdown);

        expect(result.contentMarkdown).toContain('|---');
        expect(result.contentMarkdown).toContain('Name');
        expect(result.contentMarkdown).toContain('Foo');
    });
});
